   async function (this: SessionControlWorld, harness: string) {
     const path = HARNESS_ROUTE[harness];
     if (!path) throw new Error(`Unknown harness "${harness}"`);
+    // page.goto defaults to waitUntil: 'load' which fires AFTER
+    // 'domcontentloaded', so an explicit waitForLoadState here would be a
+    // no-op. The original `networkidle` wait timed out indefinitely because
+    // App.tsx mounts useBacklogProvider on every page and useBacklogEvents
+    // opens an SSE connection — Playwright never sees the network go quiet.
+    // The subsequent assertion steps each gate on specific elements, so no
+    // additional wait is needed here.
     await this.page.goto(`${this.baseUrl}${path}`);
-    await this.page.waitForLoadState('networkidle');
   }
 );
